    "inlineSchema": "// RentFlow - Multi-Tenant Property Management SaaS\n// Auth & Multi-Tenant Module Schema\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─── Enums ───────────────────────────────────────────────────────────────────\n\nenum RoleType {\n  ADMIN\n  MANAGER\n  ACCOUNTANT\n  TENANT\n  OWNER\n}\n\nenum UserStatus {\n  ACTIVE\n  INACTIVE\n  INVITED\n  SUSPENDED\n}\n\nenum CompanyStatus {\n  ACTIVE\n  TRIAL\n  SUSPENDED\n  CANCELLED\n}\n\n// ─── Multi-Tenant Core ────────────────────────────────────────────────────────\n\nmodel Company {\n  id        String        @id @default(cuid())\n  name      String\n  slug      String        @unique\n  email     String?\n  phone     String?\n  address   String?\n  logo      String?\n  status    CompanyStatus @default(TRIAL)\n  timezone  String        @default(\"UTC\")\n  locale    String        @default(\"en\")\n  metadata  Json?\n  createdAt DateTime      @default(now())\n  updatedAt DateTime      @updatedAt\n  deletedAt DateTime?\n\n  users      User[]\n  tenants    Tenant[]\n  owners     Owner[]\n  properties Property[]\n\n  @@map(\"companies\")\n}\n\nmodel Role {\n  id        String   @id @default(cuid())\n  type      RoleType @unique\n  name      String\n  slug      String   @unique\n  level     Int // Higher = more permissions (ADMIN=100, MANAGER=80, ACCOUNTANT=60, OWNER=40, TENANT=20)\n  isSystem  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  users UserRole[]\n\n  @@map(\"roles\")\n}\n\nmodel User {\n  id                String     @id @default(cuid())\n  email             String     @unique\n  passwordHash      String\n  firstName         String\n  lastName          String\n  phone             String?\n  avatar            String?\n  status            UserStatus @default(INVITED)\n  isOwner           Boolean    @default(false) // Is the user the company owner?\n  lastLoginAt       DateTime?\n  passwordChangedAt DateTime?\n  twoFactorEnabled  Boolean    @default(false)\n  twoFactorSecret   String?\n  companyId         String\n  company           Company    @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  createdAt         DateTime   @default(now())\n  updatedAt         DateTime   @updatedAt\n  deletedAt         DateTime?\n\n  roles             UserRole[]\n  refreshTokens     RefreshToken[]\n  createdProperties Property[]     @relation(\"PropertyCreator\")\n  updatedProperties Property[]     @relation(\"PropertyUpdater\")\n\n  @@unique([companyId, email])\n  @@map(\"users\")\n}\n\nmodel UserRole {\n  id        String   @id @default(cuid())\n  userId    String\n  roleId    String\n  companyId String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  role      Role     @relation(fields: [roleId], references: [id])\n  createdAt DateTime @default(now())\n\n  @@unique([userId, roleId, companyId])\n  @@map(\"user_roles\")\n}\n\nmodel RefreshToken {\n  id        String    @id @default(cuid())\n  token     String    @unique\n  userId    String\n  user      User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  companyId String\n  expiresAt DateTime\n  createdAt DateTime  @default(now())\n  revokedAt DateTime?\n\n  @@index([token])\n  @@index([userId])\n  @@map(\"refresh_tokens\")\n}\n\n// ─── People Module (Stubs for future modules) ────────────────────────────────\n\nmodel Tenant {\n  id        String    @id @default(cuid())\n  companyId String\n  company   Company   @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  userId    String?\n  firstName String\n  lastName  String\n  email     String\n  phone     String?\n  status    String    @default(\"ACTIVE\")\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n\n  @@map(\"tenants\")\n}\n\nmodel Owner {\n  id        String    @id @default(cuid())\n  companyId String\n  company   Company   @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  userId    String?\n  firstName String\n  lastName  String\n  email     String\n  phone     String?\n  status    String    @default(\"ACTIVE\")\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n\n  @@map(\"owners\")\n}\n\n// ─── Property Module (Stubs for future modules) ──────────────────────────────\n\nmodel Property {\n  id          String    @id @default(cuid())\n  companyId   String\n  company     Company   @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  name        String\n  type        String // APARTMENT_COMPLEX, SINGLE_FAMILY, COMMERCIAL, MIXED_USE\n  status      String    @default(\"ACTIVE\")\n  description String?\n  address     String\n  city        String\n  state       String\n  zipCode     String\n  country     String    @default(\"US\")\n  totalUnits  Int       @default(0)\n  yearBuilt   Int?\n  amenities   Json?\n  images      Json?\n  metadata    Json?\n  createdById String?\n  createdBy   User?     @relation(\"PropertyCreator\", fields: [createdById], references: [id])\n  updatedById String?\n  updatedBy   User?     @relation(\"PropertyUpdater\", fields: [updatedById], references: [id])\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  deletedAt   DateTime?\n\n  @@index([companyId])\n  @@index([status])\n  @@map(\"properties\")\n}\n",
